typedef struct _UNI_GLYPHSETDATA {   DWORD dwSize;
DWORD dwVersion;   DWORD dwFlags;
LONG  lPredefinedID;   DWORD dwGlyphCount;
DWORD dwRunCount;   DWORD loRunOffset;
DWORD dwCodePageCount;   DWORD loCodePageOffset;   DWORD loMapTableOffset;   DWORD dwReserved[2];
} UNI_GLYPHSETDATA, *PUNI_GLYPHSETDATA;
成员 dwSize
指定 .gtt 文件的总大小（以字节为单位）。 请注意，这是用于定义文件的所有结构的总大小。
此值不是UNI_GLYPHSETDATA结构的大小。 dwVersion
指定文件版本号，由名称格式为 UNI_GLYPHSETDATA_VERSION_x_x的常量在 prntfont.h 中定
义。 dwFlags 未使用。
lPredefinedID
指定 prntfont.h 中定义的CC_前缀代码转换标识符之一。 dwGlyphCount
指定此字体提供的字形数。
dwRunCount
指定由 loRunOffset指向的数组中 GLYPHRUN 结构的数目。 loRunOffset
指定从UNI_GLYPHSETDATA结构的开头到 GLYPHRUN 结构的数组的开头的字节偏移量。 dwCodePageCount
指定由 loCodePageOffset指向的数组中的 UNI_CODEPAGEINFO 结构数。 loCodePageOffset
指定从UNI_GLYPHSETDATA结构的开头到 UNI_CODEPAGEINFO 结构的数组的开头的字节偏移量。
loMapTableOffset
指定从UNI_GLYPHSETDATA结构的开头到 MAPTABLE 结构的开头的字节偏移量。 dwReserved[2]
保留供系统使用。

